// Unit 5. La routine quotidienne
// Daily Routine, Time & -er Verbs

import COVERAGE_U05 from './_coverage_u05.js';

export default {n:5,lang:"fr",srcLang:"en",track:"v2",title:"La routine quotidienne",sub:"Daily Routine, Time & -er Verbs",icon:"⏰",level:"A1.2",color:"#7B5EE8",lessons:[
  {id:"fre5l1",title:"Les verbes en -er",icon:"📝",xp:15,board:true,steps:[
        {type:"intro",title:"Les verbes en -er",desc:"About 90% of French verbs follow the -er pattern. Learn this ONE pattern and you unlock hundreds of verbs. Parler was the preview. Now master the full system.",goals:["Conjugate -er verbs in all 6 persons","Recognize the silent endings","Apply the pattern to new verbs"]},
        {type:"teach",trg:"parler",src:"to speak",pos:"verb",gender:null,phonetic:"par-LAY",note:"The model -er verb. Remove -er, add endings:\nje parle, tu parles, il/elle parle\nnous parlons, vous parlez, ils/elles parlent\nNote: je, tu, il, ils forms all sound the SAME!",example:"A: Tu parles français?\nB: Oui, je parle français et anglais.\nA: Nous parlons aussi espagnol!",exampleSrc:"A: Do you speak French?\nB: Yes, I speak French and English.\nA: We also speak Spanish!",funFact:"To speak. From 'parabolare' (to speak in parables). Same root as English 'parable.' Group-1 model verb."},
        {type:"tip",title:"The -er Verb Pattern: One Pattern, Hundreds of Verbs",deepDive:{
          title:"Why are so many endings silent?",
          text:"Old French pronounced all these endings. Over centuries, final unstressed syllables eroded.\n\nLatin: parlo, parlas, parlat, parlant\nOld French: parle, parles, parle, parlent (all pronounced)\nModern French: parle, parles, parle, parlent (all sound the same: PAHRL)\n\nThis is why French spelling looks so different from pronunciation. The spelling preserves medieval forms that the spoken language has simplified.\n\nFor learners: you hear 4 forms (je/tu/il/ils = same, nous, vous, on). Writing has 6 forms."
        },text:"-er verb conjugation (present tense):\n\nje + stem + e (I)\ntu + stem + es (you, informal)\nil/elle/on + stem + e (he/she/one)\nnous + stem + ons (we)\nvous + stem + ez (you, formal/plural)\nils/elles + stem + ent (they)\n\nThe stem = verb minus -er: parler > parl-\n\nCRITICAL: je, tu, il, ils endings (-e, -es, -e, -ent) are ALL SILENT.\nOnly nous (-ons) and vous (-ez) have audible endings.\nSo parle, parles, parle, parlent all sound like PAHRL."},
        {type:"teach",trg:"habiter",src:"to live (somewhere)",pos:"verb",gender:null,phonetic:"ah-bee-TAY",note:"Habiter = to live (at a place). Regular -er verb.\nJ'habite (elision: je + habite).\nHabiter à + city: J'habite à Paris.",example:"A: Où habites-tu?\nB: J'habite à Paris.\nA: Et tes parents?\nB: Ils habitent à Lyon.",exampleSrc:"A: Where do you live?\nB: I live in Paris.\nA: And your parents?\nB: They live in Lyon.",funFact:"To live (somewhere). Latin 'habitare' (to dwell). Same root as English 'habitat.' Silent h-."},
        {type:"teach",trg:"travailler",src:"to work",pos:"verb",gender:null,phonetic:"trah-vah-YAY",note:"Travailler = to work. Regular -er verb.\nJe travaille, tu travailles, il travaille.\nThe -aille sounds like AH-yuh.",example:"A: Tu travailles où?\nB: Je travaille dans un bureau.\nA: Et ta femme?\nB: Elle travaille à l'hôpital.",exampleSrc:"A: Where do you work?\nB: I work in an office.\nA: And your wife?\nB: She works at the hospital.",funFact:"To work. Latin 'tripaliare' (torture). Dark etymology; work = torture instrument. Shared with Spanish trabajar."},
        {type:"teach",trg:"manger",src:"to eat",pos:"verb",gender:null,phonetic:"mon-ZHAY",note:"Manger = to eat. Almost regular -er verb.\nSmall exception: nous mangEONS (keep the E to preserve the ZH sound).\nJe mange, tu manges, nous mangeons.",example:"A: Qu'est-ce que tu manges?\nB: Je mange une salade.\nA: Nous mangeons au restaurant ce soir.",exampleSrc:"A: What are you eating?\nB: I am eating a salad.\nA: We are eating at the restaurant tonight.",funFact:"To eat. Latin 'manducare' (to chew). Same root as English 'mandible.' Keeps 'e' before 'a' (nous mangeons)."},
        {type:"teach",trg:"regarder",src:"to watch / to look at",pos:"verb",gender:null,phonetic:"ruh-gar-DAY",note:"Regarder = to watch/look at. Regular -er verb.\nJe regarde la télé = I watch TV.\nRegarder needs a direct object, no preposition.",example:"A: Tu regardes quoi?\nB: Je regarde un film.\nA: C'est bien?\nB: Oui, c'est super!",exampleSrc:"A: What are you watching?\nB: I am watching a movie.\nA: Is it good?\nB: Yes, it's great!",funFact:"To watch / look at. Germanic origin. Re- + garder (to keep). Literally 'to look at again.'"},
        {type:"mc",q:"The -er verb meaning 'to speak' has a conjugation base. What is it?",opts:["parl","par","parle","parler"],ans:"parl",hint:"Strip the infinitive ending (-er) from the verb to reveal its stem."},
        {type:"mc",q:"'Je parle' and 'ils parlent' sound:",opts:["Different","Identical","Similar","Ils is louder"],ans:"Identical",hint:"The -e and -ent endings are both silent."},
        {type:"fb",opts:["habites","habite","habitez","habitent"],hint:"You live (informal): stem + es ending.",s:"Tu {1}  à Paris? (to live)",a:"habites"},
        {type:"mc",q:"The ONLY two -er endings you can HEAR are:",opts:["-e and -es","-e and -ent","-ons and -ez","-ons and -ent"],ans:"-ons and -ez",hint:"Nous parl___, vous parlEZ. The rest are silent."},
        {type:"match",pairs:[{trg:"je parle",src:"I speak"},{trg:"nous parlons",src:"we speak"},{trg:"vous parlez",src:"you speak (formal)"},{trg:"ils parlent",src:"they speak"}]},
        {type:"mc",q:"'Nous mangeons' keeps the E because:",opts:["It is formal","It is plural","Manger is irregular","Without E, the G would sound like GUH"],ans:"Without E, the G would sound like GUH",hint:"The E keeps the soft ZH ___ before -ons."},
        {type:"fb",opts:["travaille","travailles","travaillent","travailler"],hint:"She works: third person singular, stem + e.",s:"Elle {1} dans un hôpital. (to work)",a:"travaille"},
        {type:"mc",q:"How many DIFFERENT sounds does a regular -er verb have in present tense?",opts:["Three","Four","Six","Two"],ans:"Three",hint:"je/tu/il/ils = same, nous = different, vous = different."},
        {type:"fb",opts:["regardons","regarde","regardez","regardent"],hint:"We watch: nous + stem + ons.",s:"Nous {1} la télé le soir. (to watch)",a:"regardons"},
        {type:"mc",q:"To conjugate any -er verb, you:",opts:["Add -er to the subject","Remove -er and add the person ending","Change the first letter","Add -ment"],ans:"Remove -er and add the person ending",hint:"Infinitive minus -er = stem. Stem + ___ = conjugated."},
        {type:"fb",opts:["écoutent","écoute","écoutons","écoutez"],hint:"They (feminine) listen: third person plural -er ending.",s:"Elles {1} la radio tous les matins. (to listen)",a:"écoutent"}
  ]},
  {id:"fre5l2",title:"L'heure",icon:"🕐",xp:15,board:true,steps:[
        {type:"intro",title:"L'heure",desc:"Learn to tell time in French. France uses the 24-hour clock officially, but 12-hour is common in speech.",goals:["Ask and tell the time","Use 24-hour and 12-hour formats","Say half, quarter, and minutes"]},
        {type:"teach",trg:"Quelle heure est-il?",src:"What time is it?",pos:"num",gender:null,phonetic:"kel UHR ay-TEEL",note:"The formal way to ask the time.\nIl est + number + heure(s) = It is ... o'clock.\nAlternative: Vous avez l'heure? (Do you have the time?)",example:"A: Quelle heure est-il?\nB: Il est trois heures.\nA: Merci!",exampleSrc:"A: What time is it?\nB: It is three o'clock.\nA: Thank you!",funFact:"What time is it? Quelle (fem) agrees with heure (fem). Standard time-question."},
        {type:"teach",trg:"Il est ... heure(s)",src:"It is ... o'clock",pos:"verb",gender:null,phonetic:"eel ay ... UHR",note:"Il est une heure = It is one o'clock (singular: heure).\nIl est deux heures = It is two (plural: heures).\nIl est midi = It is noon. Il est minuit = It is midnight.",example:"A: Il est quelle heure?\nB: Il est huit heures.\nA: Déjà? Je suis en retard!",exampleSrc:"A: What time is it?\nB: It is eight o'clock.\nA: Already? I am late!",funFact:"'It is ... o'clock.' 'Il' impersonal + 'est' + number + 'heure(s).' Singular 'heure' for 1; plural 'heures' for 2+. 'Il est une heure' (1pm)."},
        {type:"teach",trg:"... et demie / ... et quart / ... moins le quart",src:"... half past / ... quarter past / ... quarter to",pos:"intj",gender:null,phonetic:"ay duh-MEE / ay KAHR / mwan luh KAHR",note:"Et demie = and half (2:30).\nEt quart = and quarter (2:15).\nMoins le quart = minus the quarter (2:45).\nFor minutes: Il est deux heures vingt (2:20).",example:"A: Il est quelle heure?\nB: Il est deux heures et demie.\nA: Et le cours commence à trois heures moins le quart?",exampleSrc:"A: What time is it?\nB: It is half past two.\nA: And the class starts at quarter to three?",funFact:"Half past / quarter past / quarter to. Time idioms. 'Et demie' (and half), 'et quart' (and quarter), 'moins le quart' (minus the quarter). Systematic clock vocabulary."},
        {type:"teach",trg:"à ... heure(s)",src:"at ... o'clock",pos:"intj",gender:null,phonetic:"ah ... UHR",note:"À = at (for time).\nÀ sept heures = at seven o'clock.\nÀ midi = at noon. À minuit = at midnight.",example:"A: Tu te lèves à quelle heure?\nB: Je me lève à sept heures.\nA: C'est tôt!",exampleSrc:"A: What time do you get up?\nB: I get up at seven.\nA: That's early!",funFact:"At ... o'clock. 'À' (at) + hour. Singular 'heure' for 1; plural 'heures' for 2+. Position question: 'à quelle heure?' (at what time?)."},
        {type:"tip",title:"12-Hour vs 24-Hour",deepDive:{
          title:"Du matin, de l'après-midi, du soir",
          text:"To specify AM/PM in 12-hour format:\n\ndu matin = in the morning (AM)\nde l'après-midi = in the afternoon (PM)\ndu soir = in the evening (PM)\n\nIl est trois heures du matin = 3 AM.\nIl est trois heures de l'après-midi = 3 PM.\nIl est huit heures du soir = 8 PM.\n\nIn 24-hour format, these are unnecessary: 15h00 is already unambiguous."
        },text:"Official French time is 24-hour (like military time):\n\n13h00 = 1 PM. 15h30 = 3:30 PM. 20h00 = 8 PM.\n\nIn conversation, 12-hour is common:\nIl est trois heures (could be 3 AM or 3 PM).\nContext or du matin/de l'après-midi/du soir clarifies.\n\nKey times:\nMidi = noon (12:00). Minuit = midnight (00:00).\nThese replace douze heures."},
        {type:"teach",trg:"tôt / tard",src:"early / late",pos:"intj",gender:null,phonetic:"TOH / TAHR",note:"Tôt = early. Tard = late.\nC'est tôt! = That's early! C'est tard! = That's late!\nTrop tôt = too early. Trop tard = too late.",example:"A: Tu te couches tôt ou tard?\nB: Assez tard. Vers minuit.\nA: C'est tard!",exampleSrc:"A: Do you go to bed early or late?\nB: Quite late. Around midnight.\nA: That's late!",funFact:"Early / late. 'Tôt' from Latin 'tosto' (cooked/hot, metaphor for 'ready soon'). 'Tard' from Latin 'tarde'; same root as English 'tardy.'"},
        {type:"mc",q:"'Il est trois heures et demie' means:",opts:["3:30","3:15","3:45","3:00"],ans:"3:30",hint:"Et demie = and half. Half past three."},
        {type:"mc",q:"'Midi' means:",opts:["Midnight","Noon","Midday meal","Middle"],ans:"Noon",hint:"Midi = 12:00 PM. Minuit = 12:00 AM."},
        {type:"fb",opts:["moins","et","plus","avec"],hint:"Quarter TO: subtract from the next hour.",s:"Il est deux heures {1} le quart. (quarter to)",a:"moins"},
        {type:"mc",q:"In 24-hour time, 15h30 is:",opts:["3:30 AM","5:30 PM","3:30 PM","1:30 PM"],ans:"3:30 PM",hint:"15 minus 12 = 3. So 3:30 in the afternoon."},
        {type:"match",pairs:[{trg:"et demie",src:"half past"},{trg:"et quart",src:"quarter past"},{trg:"moins le quart",src:"quarter to"},{trg:"midi",src:"noon"}]},
        {type:"mc",q:"'À sept heures' means:",opts:["Since seven","Seven hours ago","For seven hours","At seven o'clock"],ans:"At seven o'clock",hint:"À = at (for time). À sept heures = at 7:00."},
        {type:"fb",opts:["heure","heures","temps","fois"],hint:"What time is it? The singular form in the question.",s:"Quelle {1} est-il? Il est neuf heures.",a:"heure"},
        {type:"mc",q:"'Il est une heure' uses singular 'heure' because:",opts:["One is singular","It is informal","Heure is always singular","It is morning"],ans:"One is singular",hint:"Une heure (1 o'clock) is ___. All others are plural."},
        {type:"fb",opts:["matin","soir","midi","nuit"],hint:"Eight o'clock in the morning.",s:"Il est huit heures du {1}. (8 AM)",a:"matin"},
        {type:"mc",q:"'Trop tard' means:",opts:["Very early","Too late","A little late","On time"],ans:"Too late",hint:"Trop = t... much. Tard = l.... Combined meaning?"},
        {type:"fb",opts:["cinq","six","sept","quatre"],hint:"The number five in French.",s:"Il est {1} heures vingt. (5:20)",a:"cinq"}
  ]},
  {id:"fre5l3",title:"Les verbes réfléchis",icon:"🪞",xp:15,board:true,steps:[
        {type:"intro",title:"Les verbes réfléchis",desc:"Reflexive verbs describe actions you do to YOURSELF: wash yourself, wake yourself up. French uses them much more than English.",goals:["Understand se + verb pattern","Use 4 daily routine reflexive verbs","Conjugate reflexive verbs correctly"]},
        {type:"teach",trg:"se lever",src:"to get up (to raise oneself)",pos:"verb",gender:null,phonetic:"suh luh-VAY",note:"Se lever = to get up (reflexive).\nJe ME lève. Tu TE lèves. Il/Elle SE lève.\nThe reflexive pronoun (me/te/se) comes BEFORE the verb.",example:"A: Tu te lèves à quelle heure?\nB: Je me lève à sept heures.\nA: C'est tôt! Moi, je me lève à neuf heures.",exampleSrc:"A: What time do you get up?\nB: I get up at seven.\nA: That's early! Me, I get up at nine.",funFact:"To get up. Se + lever (to raise). Reflexive; raise-oneself. Related to English 'levitate.'"},
        {type:"teach",trg:"se coucher",src:"to go to bed (to lay oneself down)",pos:"verb",gender:null,phonetic:"suh koo-SHAY",note:"Se coucher = to go to bed (reflexive).\nJe me couche. Tu te couches. Ils se couchent.\nSame pattern as se lever: me/te/se before verb.",example:"A: Tu te couches à quelle heure?\nB: Je me couche à onze heures.\nA: Et les enfants?\nB: Ils se couchent à huit heures.",exampleSrc:"A: What time do you go to bed?\nB: I go to bed at eleven.\nA: And the children?\nB: They go to bed at eight.",funFact:"To go to bed. Se + coucher (to lay). Reflexive. Related to English 'couch.'"},
        {type:"teach",trg:"se réveiller",src:"to wake up",pos:"verb",gender:null,phonetic:"suh ray-vay-YAY",note:"Se réveiller = to wake up (reflexive).\nJe me réveille. Tu te réveilles.\nThe verb part conjugates normally (-er pattern).",example:"A: Tu te réveilles facilement?\nB: Non, je me réveille difficilement.\nA: Moi, je me réveille avec une alarme.",exampleSrc:"A: Do you wake up easily?\nB: No, I wake up with difficulty.\nA: Me, I wake up with an alarm.",funFact:"To wake up. Se + réveiller (from réveil = awakening). Reflexive."},
        {type:"teach",trg:"se laver",src:"to wash oneself",pos:"verb",gender:null,phonetic:"suh lah-VAY",note:"Se laver = to wash (oneself) (reflexive).\nJe me lave. Tu te laves. Elle se lave.\nSe laver les mains = to wash one's hands.",example:"A: Tu te laves le matin ou le soir?\nB: Je me lave le matin.\nA: Avant ou après le petit déjeuner?",exampleSrc:"A: Do you wash in the morning or evening?\nB: I wash in the morning.\nA: Before or after breakfast?",funFact:"To wash oneself. Se + laver (from Latin 'lavare'). Same root as 'lavatory.'"},
        {type:"tip",title:"How Reflexive Verbs Work",deepDive:{
          title:"Why so many reflexive verbs in French?",
          text:"French uses reflexive verbs for many actions that English expresses differently:\n\nse lever = to get up (raise yourself)\nse coucher = to go to bed (lay yourself down)\nse laver = to wash (wash yourself)\nse réveiller = to wake up (wake yourself)\nse brosser les dents = to brush your teeth (brush yourself the teeth)\nse maquiller = to put on makeup (make yourself up)\ns'habiller = to get dressed (dress yourself)\n\nIn English, the yourself is usually implied. In French, it is explicit. This reflects a grammatical tradition from Latin where the reflexive was standard for self-directed actions."
        },text:"Reflexive verbs have TWO parts:\n1. A reflexive pronoun (me, te, se, nous, vous, se)\n2. The verb (conjugated normally)\n\nje ME lève (I get up = I raise myself)\ntu TE lèves (you get up)\nil/elle SE lève (he/she gets up)\nnous NOUS levons (we get up)\nvous VOUS levez (you get up)\nils/elles SE lèvent (they get up)\n\nThe pronoun matches the subject and goes BEFORE the verb.\nThe verb part follows normal -er conjugation."},
        {type:"teach",trg:"le matin / le soir",src:"in the morning / in the evening",pos:"noun",gender:"m",phonetic:"luh mah-TAN / luh SWAHR",note:"Le matin = in the morning. Le soir = in the evening.\nFrench uses le + time of day (no preposition: NOT dans le matin).\nL'après-midi = in the afternoon.",example:"A: Tu te laves le matin ou le soir?\nB: Le matin. Et je me brosse les dents le matin et le soir.\nA: Bonne hygiène!",exampleSrc:"A: Do you wash in the morning or the evening?\nB: In the morning. And I brush my teeth morning and evening.\nA: Good hygiene!",funFact:"In the morning / in the evening. 'Matin' from Latin 'matutinus' (of the morning). 'Soir' from Latin 'sero' (late). Day-phase vocabulary."},
        {type:"mc",q:"In 'je me lève', the 'me' is:",opts:["A reflexive pronoun (myself)","An article (definite/indefinite)","A possessive determiner","A preposition before verbs"],ans:"A reflexive pronoun (myself)",hint:"Me = ___. The action reflects back to the subject."},
        {type:"mc",q:"Reflexive pronouns go:",opts:["After the verb","Before the verb","After the subject","At the end"],ans:"Before the verb",hint:"Je ME lève. Tu TE couches. The pronoun is between subject and ___."},
        {type:"fb",opts:["te","me","se","nous"],hint:"You (informal) get up: which reflexive pronoun?",s:"Tu {1} lèves à quelle heure?",a:"te"},
        {type:"mc",q:"'Ils se couchent' means:",opts:["They wake up","They wash","They go to bed","They eat"],ans:"They go to bed",hint:"Se coucher = the reflexive for ending the day. What does it mean?"},
        {type:"match",pairs:[{trg:"se lever",src:"to get up"},{trg:"se coucher",src:"to go to bed"},{trg:"se réveiller",src:"to wake up"},{trg:"se laver",src:"to wash oneself"}]},
        {type:"mc",q:"The verb part of a reflexive -er verb conjugates:",opts:["Differently from regular -er verbs","Without any endings","With special reflexive endings","Normally, following the -er pattern"],ans:"Normally, following the -er pattern",hint:"The verb conjugates ___. Only the pronoun is added."},
        {type:"fb",opts:["se","me","te","nous"],hint:"She washes: third person reflexive pronoun.",s:"Elle {1} lave les mains avant de manger.",a:"se"},
        {type:"mc",q:"'Le matin' means 'in the morning' without any preposition because:",opts:["French uses le + time of day","It is informal","Matin is special","Le replaces dans"],ans:"French uses le + time of day",hint:"Le matin, le soir, l'après-midi: definite article for ___ periods."},
        {type:"fb",opts:["réveille","lève","couche","lave"],hint:"I wake up: the reflexive verb for coming out of sleep.",s:"Je me {1} à six heures et demie. (to wake up)",a:"réveille"},
        {type:"mc",q:"The nous form of 'se lever' is:",opts:["Nous se levons","Nous nous levons","Nous levons nous","On se lève"],ans:"Nous nous levons",hint:"___ + ___ (reflexive pronoun) + ___."},
        {type:"fb",opts:["t'","se","me","nous"],hint:"Second person reflexive before a vowel: elided form.",s:"Tu {1} habilles vite le matin. (yourself)",a:"t'"}
  ]},
  {id:"fre5l4",title:"Ma journée",icon:"🌅",xp:15,board:true,steps:[
        {type:"intro",title:"Ma journée",desc:"Describe a typical day from morning to night. Combine time, reflexive verbs, and -er verbs into a flowing daily narrative.",goals:["Describe a full daily routine","Use time expressions naturally","Sequence actions with puis, ensuite, après"]},
        {type:"teach",trg:"D'abord... puis... ensuite... enfin",src:"First... then... next... finally",pos:"intj",gender:null,phonetic:"dah-BOR... PWEE... on-SWEET... on-FAN",note:"Sequence words for describing routines:\nD'abord = first. Puis = then. Ensuite = next. Enfin = finally.\nAprès = after. Avant = before.",example:"A: Qu'est-ce que tu fais le matin?\nB: D'abord, je me réveille. Puis, je me lève. Ensuite, je me lave.\nA: Et après?\nB: Enfin, je prends le petit déjeuner.",exampleSrc:"A: What do you do in the morning?\nB: First, I wake up. Then, I get up. Next, I wash.\nA: And after?\nB: Finally, I have breakfast.",funFact:"First... then... next... finally. Narrative connectors. D'abord = at first. Enfin = at last, from 'en' + 'fin' (at end)."},
        {type:"teach",trg:"prendre",src:"to take / to have (food/drink)",pos:"verb",gender:null,phonetic:"PRONDR",note:"Prendre = to take/have (irregular verb!).\nJe prends, tu prends, il prend (no S!)\nNous prenons, vous prenez, ils prennent.\nUsed for meals: prendre le petit déjeuner = to have breakfast.",example:"A: Tu prends quoi au petit déjeuner?\nB: Je prends un café et un croissant.\nA: Moi, je prends du thé.",exampleSrc:"A: What do you have for breakfast?\nB: I have a coffee and a croissant.\nA: Me, I have tea.",funFact:"To take / to have (food/drink). Irregular stem pren-."},
        {type:"teach",trg:"aller",src:"to go",pos:"verb",gender:null,phonetic:"ah-LAY",note:"Aller = to go (highly irregular!).\nJe vais, tu vas, il va\nNous allons, vous allez, ils vont.\nAller + à = go to: je vais au travail.",example:"A: Tu vas au travail à quelle heure?\nB: Je vais au travail à huit heures.\nA: Tu y vas comment?\nB: J'y vais en métro.",exampleSrc:"A: What time do you go to work?\nB: I go to work at eight.\nA: How do you get there?\nB: I go by metro.",funFact:"To go. IRREGULAR; not a regular -er verb despite the ending. One of most irregular French verbs."},
        {type:"teach",trg:"faire (du sport / la cuisine)",src:"to do (sport / cooking)",pos:"verb",gender:null,phonetic:"FEHR",note:"Faire = to do/make (irregular).\nJe fais, tu fais, il fait\nNous faisons, vous faites, ils font.\nFaire du sport = to exercise. Faire la cuisine = to cook.",example:"A: Tu fais du sport?\nB: Oui, je fais du sport le soir.\nA: Et tu fais la cuisine aussi?\nB: Oui, j'adore faire la cuisine!",exampleSrc:"A: Do you do sport?\nB: Yes, I do sport in the evening.\nA: And you cook too?\nB: Yes, I love cooking!",funFact:"'To do (sport / cooking).' Irregular verb 'faire.' Takes partitive 'du/de la' for activities. 'Faire du sport' = do sports (regularly)."},
        {type:"tip",title:"A Model Daily Routine",deepDive:{
          title:"Irregular verbs in daily routine",
          text:"Daily routine uses several irregular verbs:\n\nPrendre (to take/have): je prends, tu prends, il prend\nAller (to go): je vais, tu vas, il va\nFaire (to do/make): je fais, tu fais, il fait\n\nThese three irregulars are among the most common French verbs. Memorize their present tense forms. They appear in almost every conversation about daily life.\n\nRegular -er verbs in routine: travailler, déjeuner, dîner, regarder, rentrer (to come home)."
        },text:"A typical French daily routine:\n\nLe matin:\nJe me réveille à sept heures.\nJe me lève et je me lave.\nJe prends le petit déjeuner.\nJe vais au travail à huit heures.\n\nL'après-midi:\nJe déjeune à midi.\nJe travaille jusqu'à cinq heures.\n\nLe soir:\nJe rentre à la maison à six heures.\nJe fais la cuisine.\nJe dîne à sept heures et demie.\nJe regarde la télé.\nJe me couche à onze heures."},
        {type:"teach",trg:"rentrer",src:"to come home / to return",pos:"verb",gender:null,phonetic:"ron-TRAY",note:"Rentrer = to come home / to go back. Regular -er verb.\nJe rentre à la maison = I come home.\nIl rentre du travail = He comes back from work.",example:"A: Tu rentres à quelle heure?\nB: Je rentre à six heures.\nA: C'est tôt!",exampleSrc:"A: What time do you come home?\nB: I come home at six.\nA: That's early!",funFact:"To come home / return. Re- + entrer (to enter). Literally 'to re-enter.' Takes être."},
        {type:"mc",q:"The correct sequence is:",opts:["D'abord, puis, ensuite, enfin","Ensuite, d'abord, puis, enfin","Enfin, d'abord, ensuite, puis","Puis, enfin, d'abord, ensuite"],ans:"D'abord, puis, ensuite, enfin",hint:"First, then, next, finally: the logical order."},
        {type:"mc",q:"'Je prends le petit déjeuner' uses prendre because:",opts:["Prendre means to eat","French uses prendre (to take/have) for meals","Prendre means to cook","It is informal"],ans:"French uses prendre (to take/have) for meals",hint:"___ le petit déjeuner = to have breakfast."},
        {type:"fb",opts:["vais","vas","va","aller"],hint:"I go: first person singular of aller.",s:"Je {1} au travail à huit heures. (to go)",a:"vais"},
        {type:"mc",q:"'Faire du sport' means:",opts:["To watch sport","To like sport","To do sport / to exercise","To play a sport"],ans:"To do sport / to exercise",hint:"Faire = to do. Du s... = some s...."},
        {type:"match",pairs:[{trg:"se réveiller",src:"to wake up"},{trg:"prendre le petit déjeuner",src:"to have breakfast"},{trg:"aller au travail",src:"to go to work"},{trg:"rentrer à la maison",src:"to come home"}]},
        {type:"mc",q:"Which verbs are IRREGULAR?",opts:["Habiter, travailler, regarder","Parler, manger, rentrer","Se lever, se coucher, se laver","Prendre, aller, faire"],ans:"Prendre, aller, faire",hint:"These three do not follow the -er pattern."},
        {type:"fb",opts:["fait","fais","faire","font"],hint:"She does/makes: third person singular of faire.",s:"Elle {1} la cuisine tous les soirs. (to do/make)",a:"fait"},
        {type:"mc",q:"'Je rentre à la maison' means:",opts:["I come home","I leave the house","I clean the house","I build a house"],ans:"I come home",hint:"Rentrer = to c... back/h.... Regular -er verb."},
        {type:"fb",opts:["puis","enfin","d'abord","avant"],hint:"First I get up, THEN I wash. Second in the sequence.",s:"D'abord je me lève, {1} je me lave.",a:"puis"},
        {type:"mc",q:"In 'nous prenons', the conjugation is irregular because:",opts:["Nous is special","Prendre does not follow the -er pattern","Prenons sounds better","It is a reflexive verb"],ans:"Prendre does not follow the -er pattern",hint:"___ is an -re verb with its own irregular forms."},
        {type:"fb",opts:["se","me","te","nous"],hint:"She goes to bed: third person reflexive pronoun.",s:"Le soir, elle {1} couche à vingt-deux heures.",a:"se"}
  ]},
  {id:"fre5l5",title:"Les jours de la semaine",icon:"📅",xp:15,board:true,steps:[
        {type:"intro",title:"Les jours de la semaine",desc:"Learn the days of the week. In France, the week starts on Monday (lundi), not Sunday. Days are never capitalized.",goals:["Name all 7 days","Know that days are lowercase and masculine","Use le + day for habitual actions"]},
        {type:"teach",trg:"lundi, mardi, mercredi",src:"Monday, Tuesday, Wednesday",pos:"intj",gender:null,phonetic:"lun-DEE, mar-DEE, mehr-kruh-DEE",note:"Lundi, mardi, mercredi = Mon, Tue, Wed.\nAlways lowercase in French (not capitalized).\nAll masculine: le lundi = on Mondays (habitual).",example:"A: Tu travailles lundi?\nB: Oui, je travaille lundi et mardi.\nA: Et mercredi?\nB: Mercredi, je suis libre!",exampleSrc:"A: Do you work Monday?\nB: Yes, I work Monday and Tuesday.\nA: And Wednesday?\nB: Wednesday, I am free!",funFact:"Monday, Tuesday, Wednesday. Latin roots: lunae-dies (moon-day), martis-dies (Mars-day), mercurii-dies (Mercury-day). Pagan planetary gods."},
        {type:"teach",trg:"jeudi, vendredi",src:"Thursday, Friday",pos:"intj",gender:null,phonetic:"zhuh-DEE, von-druh-DEE",note:"Jeudi = Thursday. Vendredi = Friday.\nJeudi comes from Jupiter (Jovis dies).\nVendredi from Venus (Veneris dies).",example:"A: Le cours est jeudi ou vendredi?\nB: Jeudi. Et vendredi, on fait la fête!\nA: Super!",exampleSrc:"A: Is the class Thursday or Friday?\nB: Thursday. And Friday, we party!\nA: Great!",funFact:"Thursday, Friday. From Latin Jovis-dies (Jupiter-day), Veneris-dies (Venus-day). English Thursday/Friday use Germanic equivalents (Thor/Frigg)."},
        {type:"teach",trg:"samedi, dimanche",src:"Saturday, Sunday",pos:"intj",gender:null,phonetic:"sam-DEE, dee-MONSH",note:"Samedi = Saturday. Dimanche = Sunday.\nLe week-end = the weekend (borrowed from English).\nFrench week starts Monday, ends Sunday.",example:"A: Qu'est-ce que tu fais le week-end?\nB: Samedi, je fais du sport. Dimanche, je me repose.\nA: Bon week-end!",exampleSrc:"A: What do you do on the weekend?\nB: Saturday, I exercise. Sunday, I rest.\nA: Have a good weekend!",funFact:"Saturday, Sunday. 'Samedi' from Latin 'sabbati-dies' (sabbath day, Hebrew origin). 'Dimanche' from 'dies dominicus' (Lord's day, Christian)."},
        {type:"tip",title:"Le lundi vs Lundi",deepDive:{
          title:"Origins of French day names",
          text:"French days come from Latin/Roman gods and planets:\n\nLundi = Moon day (Latin: Lunae dies, English: Monday)\nMardi = Mars day (Latin: Martis dies, English: Tuesday)\nMercredi = Mercury day (Latin: Mercurii dies)\nJeudi = Jupiter day (Latin: Jovis dies, English: Thursday from Thor)\nVendredi = Venus day (Latin: Veneris dies, English: Friday from Freya)\nSamedi = Saturn day (Latin: Saturni dies, English: Saturday)\nDimanche = Lord's day (Latin: Dominica dies, English: Sunday)\n\nNotice: English replaced most Roman gods with Norse equivalents, but French kept the Latin."
        },text:"Critical difference:\n\nLundi = this Monday / on Monday (specific, once)\nLe lundi = on Mondays (every Monday, habitual)\n\nJe travaille lundi. = I work this Monday.\nJe travaille le lundi. = I work on Mondays (every week).\n\nThe definite article le makes it habitual.\nThis pattern works for all time expressions:\nLe matin = every morning. Le soir = every evening."},
        {type:"teach",trg:"le week-end",src:"the weekend",pos:"noun",gender:"m",phonetic:"luh week-END",note:"Le week-end = the weekend (English loanword!).\nBon week-end! = Have a good weekend!\nLe week-end = habitual. Ce week-end = this weekend.",example:"A: Tu fais quoi le week-end?\nB: Le week-end, je me repose.\nA: Moi, je fais du sport le samedi.",exampleSrc:"A: What do you do on weekends?\nB: On weekends, I rest.\nA: Me, I exercise on Saturdays.",funFact:"Cognate with English 'weekend'. Many English words were borrowed from French after 1066."},
        {type:"mc",q:"French days of the week are:",opts:["Never capitalized","Always capitalized","Capitalized at sentence start only","Capitalized on calendars"],ans:"Never capitalized",hint:"Lundi, mardi, mercredi: always lowercase."},
        {type:"mc",q:"'Le lundi' vs 'lundi' means:",opts:["Formal vs casual","Every Monday vs this Monday","Past vs present","Morning vs evening"],ans:"Every Monday vs this Monday",hint:"Le + day = habitual. Day alone = specific occasion."},
        {type:"fb",opts:["lundi","le lundi","un lundi","au lundi"],hint:"This specific Monday, not every Monday.",s:"Je travaille {1} et mardi. (this Monday)",a:"lundi"},
        {type:"mc",q:"In France, the week starts on:",opts:["Sunday","Saturday","Monday","It varies"],ans:"Monday",hint:"French week: lundi to dimanche (Mon to Sun)."},
        {type:"match",pairs:[{trg:"lundi",src:"Monday"},{trg:"mercredi",src:"Wednesday"},{trg:"vendredi",src:"Friday"},{trg:"dimanche",src:"Sunday"}]},
        {type:"mc",q:"'Mardi' comes from the planet/god:",opts:["Moon","Jupiter","Mercury","Mars"],ans:"Mars",hint:"Mardi comes from the Latin Martis dies. Which Roman god?"},
        {type:"fb",opts:["Le","Ce","Un","En"],hint:"Habitual: LE + day = every Saturday.",s:"{1} samedi, je fais du sport. (every Saturday)",a:"Le"},
        {type:"mc",q:"'Le week-end' is an English word borrowed into French:",opts:["True","False","Only in Canada","Only in informal speech"],ans:"True",hint:"French borrowed week-end directly from English."},
        {type:"mc",q:"'Bon week-end!' is said:",opts:["Monday morning","Friday/Saturday when parting","Sunday night","Any day"],ans:"Friday/Saturday when parting",hint:"Wishing someone a good weekend as you part."},
        {type:"fb",opts:["ce","le","un","du"],hint:"This specific Sunday: demonstrative + day.",s:"Qu'est-ce que tu fais {1} dimanche? (this Sunday)",a:"ce"},
        {type:"mc",q:"All French day names are:",opts:["Feminine","Neutral","Masculine","Mixed"],ans:"Masculine",hint:"Le lundi, le mardi: notice the article that precedes them."},
        {type:"fb",opts:["lundi","dimanche","samedi","mardi"],hint:"In France, the week starts on this day, not Sunday.",s:"Le {1} est le premier jour de la semaine en France.",a:"lundi"}
  ]},
  {id:"fre5l6",title:"La négation",icon:"🚫",xp:15,board:true,steps:[
        {type:"intro",title:"La négation: ne...pas",desc:"French negation wraps around the verb: ne BEFORE, pas AFTER. This sandwich pattern is essential and affects articles too.",goals:["Use ne...pas for negation","Handle elision (n'...pas before vowels)","Know partitive becomes de after negation"]},
        {type:"teach",trg:"ne ... pas",src:"not",pos:"intj",gender:null,phonetic:"nuh ... PAH",note:"Ne ... pas = not. Wraps around the verb:\nJe ne parle pas. Tu ne manges pas. Il ne travaille pas.\nNe goes BEFORE the verb. Pas goes AFTER.",example:"A: Tu parles chinois?\nB: Non, je ne parle pas chinois.\nA: Et japonais?\nB: Non, je ne parle pas japonais non plus.",exampleSrc:"A: Do you speak Chinese?\nB: No, I do not speak Chinese.\nA: And Japanese?\nB: No, I do not speak Japanese either.",funFact:"Not. Two-part negation framing the verb. 'Je ne sais pas' (I don't know). 'Pas' originally meant 'step' (from Latin 'passus'); intensifier that became the main negator."},
        {type:"teach",trg:"n' ... pas (before vowels)",src:"not (before vowels)",pos:"intj",gender:null,phonetic:"n ... PAH",note:"Before vowel sounds, ne becomes n':\nJe n'aime pas. Il n'habite pas. Elle n'est pas.\nElision: ne + aime = n'aime.",example:"A: Tu n'aimes pas le fromage?\nB: Non, je n'aime pas le fromage.\nA: C'est dommage!",exampleSrc:"A: You don't like cheese?\nB: No, I don't like cheese.\nA: That's a shame!",funFact:"Cognate with English 'not (before vowels)'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"ne ... pas de",src:"not any (negation + partitive)",pos:"intj",gender:null,phonetic:"nuh ... PAH duh",note:"After ne...pas, partitive articles become DE:\nJ'ai du lait > Je n'ai pas DE lait.\nJ'ai de la soupe > Je n'ai pas DE soupe.\nIl y a des pommes > Il n'y a pas DE pommes.",example:"A: Tu as du lait?\nB: Non, je n'ai pas de lait.\nA: Et du pain?\nB: Non, je n'ai pas de pain non plus.",exampleSrc:"A: Do you have milk?\nB: No, I don't have any milk.\nA: And bread?\nB: No, I don't have any bread either.",funFact:"Not any (negation + partitive). After 'pas,' partitive articles 'un/une/du/de la/des' reduce to just 'de.' 'Je n'ai pas de livre' (I don't have a/any book)."},
        {type:"tip",title:"The Negation Sandwich",deepDive:{
          title:"Other negation words",
          text:"Ne...pas is the basic negation. French has others:\n\nne...plus = no longer (Je ne travaille plus = I no longer work)\nne...jamais = never (Je ne mange jamais de viande = I never eat meat)\nne...rien = nothing (Je ne vois rien = I see nothing)\nne...personne = nobody (Je ne connais personne = I know nobody)\n\nThey all follow the same sandwich pattern: ne + verb + negation word.\nYou will learn these in A2."
        },text:"French negation always has two parts:\n\nSubject + NE + verb + PAS + rest\nJe NE parle PAS français.\nTu NE manges PAS de viande.\nIl N'habite PAS à Paris.\n\nBefore vowels, ne becomes n':\nJe N'aime PAS. Elle N'est PAS.\n\nCRITICAL: In spoken French, ne is often dropped!\nJe parle pas. (spoken)\nJe ne parle pas. (written/formal)\n\nAlways write ne. In speech, you will hear it dropped."},
        {type:"teach",trg:"Ce n'est pas...",src:"It is not...",pos:"intj",gender:null,phonetic:"suh nay PAH",note:"Ce n'est pas = It is not.\nC'est + affirmative = C'est bon. (It's good.)\nCe n'est pas + negative = Ce n'est pas bon. (It's not good.)",example:"A: C'est du café?\nB: Non, ce n'est pas du café. C'est du thé.\nA: Ah, pardon!",exampleSrc:"A: Is that coffee?\nB: No, it is not coffee. It's tea.\nA: Ah, sorry!",funFact:"It is not... Ce + negation + est. The c' is elided from ce before est. Negated equivalent of c'est."},
        {type:"mc",q:"'Je ne parle pas français' has negation:",opts:["Wrapped around the verb (ne...pas)","Only after the verb","Only before the verb","At the end"],ans:"Wrapped around the verb (ne...pas)",hint:"French negation uses two pieces that sandwich the conjugated element."},
        {type:"mc",q:"Before vowels, 'ne' becomes:",opts:["Non","N'","Pas","Nul"],ans:"N'",hint:"Elision happens before vowels. The E drops and an apostrophe appears."},
        {type:"fb",opts:["ne","n'","pas","non"],hint:"The first half of the negation sandwich, before the verb.",s:"Je {1} mange pas de viande.",a:"ne"},
        {type:"mc",q:"'J'ai du lait' in negative becomes:",opts:["Je n'ai pas du lait","Je n'ai pas le lait","Je n'ai pas de lait","Je n'ai du lait pas"],ans:"Je n'ai pas de lait",hint:"Negation changes partitive articles to a simpler form."},
        {type:"match",pairs:[{trg:"Je parle",src:"I speak"},{trg:"Je ne parle pas",src:"I do not speak"},{trg:"J'aime",src:"I like"},{trg:"Je n'aime pas",src:"I do not like"}]},
        {type:"mc",q:"In spoken French, 'ne' is often:",opts:["Emphasized","Replaced by pas","Doubled","Dropped"],ans:"Dropped",hint:"Spoken: je parle pas. Written: je ne parle pas."},
        {type:"fb",opts:["de","du","le","un"],hint:"After ne...pas, partitive becomes just de.",s:"Il n'y a pas {1} pain. (no bread)",a:"de"},
        {type:"mc",q:"'Ce n'est pas bon' means:",opts:["It is not good","It is very good","It is not bad","It is okay"],ans:"It is not good",hint:"Ce n'est pas = it is not. Bon = g...."},
        {type:"fb",opts:["n'","ne","ni","non"],hint:"Before a vowel (habite), ne becomes n'.",s:"Elle {1} habite pas à Paris.",a:"n'"},
        {type:"mc",q:"Which negative sentence is correct?",opts:["Je pas parle","Je ne parle pas","Je ne pas parle","Pas je ne parle"],ans:"Je ne parle pas",hint:"Remember the two-part frame: the first piece goes before the verb, the second after."},
        {type:"mc",q:"'Il n'y a pas de pommes' means:",opts:["There are some apples","There are the apples","There are no apples","Apples are not here"],ans:"There are no apples",hint:"Il n'y a pas de = t... are no / t... aren't any."},
        {type:"fb",opts:["n'","ne","ni","pas"],hint:"Before a vowel, ne becomes the elided form.",s:"Elle {1} aime pas le café.",a:"n'"}
  ]},
  {id:"fre5l7",title:"Ma semaine typique",icon:"📋",xp:15,board:true,steps:[
        {type:"intro",title:"Ma semaine typique",desc:"Describe your typical week combining everything: days, times, routine verbs, negation. This is where all Unit 5 skills connect.",goals:["Describe a typical week day by day","Use time expressions fluently","Combine positive and negative statements"]},
        {type:"teach",trg:"tous les jours",src:"every day",pos:"intj",gender:null,phonetic:"too lay ZHOOR",note:"Tous les jours = every day (literally: all the days).\nTous = all. Les jours = the days.\nTous les matins = every morning. Tous les soirs = every evening.",example:"A: Tu fais du sport?\nB: Oui, je fais du sport tous les jours.\nA: Impressionnant!",exampleSrc:"A: Do you exercise?\nB: Yes, I exercise every day.\nA: Impressive!",funFact:"Every day. 'Tous les' (all the, masc. pl.) + 'jours' (days). Regular frequency phrase."},
        {type:"teach",trg:"souvent / parfois / rarement",src:"often / sometimes / rarely",pos:"verb",gender:null,phonetic:"soo-VON / par-FWAH / rar-MON",note:"Frequency adverbs go AFTER the verb:\nJe mange souvent au restaurant.\nJe fais rarement du sport.\nJe travaille parfois le samedi.",example:"A: Tu cuisines souvent?\nB: Parfois. Je mange souvent au restaurant.\nA: Et tu fais du sport?\nB: Rarement, malheureusement!",exampleSrc:"A: Do you cook often?\nB: Sometimes. I often eat at restaurants.\nA: And do you exercise?\nB: Rarely, unfortunately!",funFact:"Often / sometimes / rarely. Frequency adverbs. 'Souvent' = often (Latin 'subinde'), 'parfois' = sometimes (par + fois = 'by times')."},
        {type:"teach",trg:"de ... à ...",src:"from ... to ...",pos:"prep",gender:null,phonetic:"duh ... ah",note:"De ... à ... = from ... to ... (for time ranges).\nDe neuf heures à cinq heures = from 9 to 5.\nDu lundi au vendredi = from Monday to Friday.",example:"A: Tu travailles de quelle heure à quelle heure?\nB: Je travaille de neuf heures à cinq heures.\nA: C'est une journée normale.",exampleSrc:"A: What hours do you work?\nB: I work from nine to five.\nA: That's a normal day.",funFact:"From ... to ... Duration phrase. De (from) + à (to) + times. Common for schedules."},
        {type:"tip",title:"Weekly Routine Template",deepDive:{
          title:"Faire les courses vs faire du shopping",
          text:"Faire les courses = to do grocery shopping (essential, weekly errands)\nFaire du shopping = to go shopping (leisure, clothes, fun)\n\nFrench distinguishes between necessity shopping (les courses) and pleasure shopping (du shopping).\n\nJe fais les courses le samedi. = I do groceries on Saturday.\nJe fais du shopping le samedi. = I go shopping on Saturday.\n\nLes courses is more common in daily routine descriptions."
        },text:"A model weekly description:\n\nLe lundi, je travaille de neuf heures à cinq heures.\nLe mardi, je fais du sport après le travail.\nLe mercredi, je ne travaille pas. Je fais les courses.\nLe jeudi, je travaille et je dîne avec des amis.\nLe vendredi, je rentre tôt. C'est le week-end!\nLe samedi, je me lève tard et je fais du sport.\nLe dimanche, je me repose.\n\nKey patterns:\nLe + day = habitual (every week)\nVerb + time = when\nNe...pas = what you don't do"},
        {type:"mc",q:"Frequency adverbs in French go:",opts:["After the verb","Before the verb","At the beginning","At the end"],ans:"After the verb",hint:"Je mange SOUVENT. Je travaille RAREMENT."},
        {type:"mc",q:"'Tous les jours' means:",opts:["Some days","Every day","All day long","Any day"],ans:"Every day",hint:"Tous = all. Les jours = the days. All the days."},
        {type:"fb",opts:["de","à","en","du"],hint:"From nine to five: the first preposition.",s:"Je travaille {1} neuf heures à cinq heures.",a:"de"},
        {type:"mc",q:"'Le mercredi, je ne travaille pas' means:",opts:["I worked last Wednesday","This Wednesday I'm free","I never work on Wednesdays","Wednesday is a holiday"],ans:"I never work on Wednesdays",hint:"Le + day = habitual. Ne...pas = negation."},
        {type:"match",pairs:[{trg:"tous les jours",src:"every day"},{trg:"souvent",src:"often"},{trg:"parfois",src:"sometimes"},{trg:"rarement",src:"rarely"}]},
        {type:"mc",q:"'Du lundi au vendredi' means:",opts:["On Monday and Friday","Between Monday and Friday","Monday or Friday","From Monday to Friday"],ans:"From Monday to Friday",hint:"Du (de + le) ... au (à + le): from ... to."},
        {type:"fb",opts:["rarement","souvent","parfois","jamais"],hint:"Frequency adverb: almost never.",s:"Je fais {1} du sport. (rarely)",a:"rarement"},
        {type:"mc",q:"'Faire les courses' means:",opts:["Do grocery shopping","Run a race","Take a course","Go to school"],ans:"Do grocery shopping",hint:"Les courses = errands/groceries. Essential s...."},
        {type:"fb",opts:["tard","tôt","vite","bien"],hint:"On Sundays I get up ___. Sleeping in!",s:"Je me lève {1} le dimanche. (late)",a:"tard"},
        {type:"mc",q:"In 'Je mange souvent au restaurant', souvent goes:",opts:["Before je","After mange","Before mange","At the end"],ans:"After mange",hint:"Frequency adverbs follow the verb directly."},
        {type:"mc",q:"'Tous les matins' means:",opts:["This morning","All morning","Every morning","Some mornings"],ans:"Every morning",hint:"Tous les = e.../all. Matins = mornings."},
        {type:"fb",opts:["Tous","Tout","Toute","Toutes"],hint:"Every day: ___ les jours. Masculine plural.",s:"{1} les jours, je me réveille à sept heures.",a:"Tous"},
        {type:"mc",q:"'Faire la grasse matinée' means:",opts:["To cook breakfast","To skip breakfast","To do morning exercises","To sleep in"],ans:"To sleep in",hint:"Grasse matinée = a 'fat morning'. A lazy morning in bed."}
  ]},
  {id:"fre5l8b",title:"Les Mois et les Saisons",icon:"📅",xp:20,board:true,steps:[
        {type:"intro",title:"Les Mois et les Saisons",desc:"Learn all 12 months and the 4 seasons in French. Months are always lowercase and masculine. Seasons use different articles depending on the preposition.",goals:["Name all 12 months","Name the 4 seasons","Use en/au with seasons correctly","Talk about birthdays and dates"]},
        {type:"teach",trg:"janvier",src:"January",pos:"verb",gender:null,note:"First month of the year. Always lowercase in French.\nUse en + month: en janvier = in January.",example:"A: Ton anniversaire, c'est quand?\nB: C'est en janvier.\nA: En janvier? Il fait froid!",exampleSrc:"A: When is your birthday?\nB: It is in January.\nA: In January? It is cold!",funFact:"January. From Latin 'Januarius' (month of Janus, god of beginnings)."},
        {type:"teach",trg:"février",src:"February",pos:"verb",gender:null,note:"The accent on é is important.\nFévrier has 28 or 29 days.",example:"A: Qu'est-ce qu'on fête en février?\nB: La Saint-Valentin, le 14 février!\nA: Ah oui, bien sûr!",exampleSrc:"A: What do we celebrate in February?\nB: Valentine's Day, February 14th!\nA: Ah yes, of course!",funFact:"February. From Latin 'Februarius' (month of purification festival Februa)."},
        {type:"teach",trg:"mars",src:"March",pos:"noun",gender:"m",note:"Same spelling as the planet Mars.\nAlways lowercase when referring to the month.",example:"A: Le printemps commence en mars?\nB: Oui, le 20 mars en général.\nA: J'adore le printemps!",exampleSrc:"A: Does spring start in March?\nB: Yes, around March 20th.\nA: I love spring!",funFact:"March. From Latin 'Martius' (month of Mars). Silent s."},
        {type:"teach",trg:"avril",src:"April",pos:"verb",gender:null,note:"En avril, ne te découvre pas d'un fil.\nFamous French proverb about April weather.",example:"A: Il pleut souvent en avril?\nB: Oui, en avril, ne te découvre pas d'un fil!\nA: C'est un proverbe?",exampleSrc:"A: Does it rain often in April?\nB: Yes, in April, don't shed a layer!\nA: Is that a proverb?",funFact:"Cognate with English 'april'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"mai",src:"May",pos:"noun",gender:"m",note:"Mai is short and easy to remember.\nMay has many public holidays in France.",example:"A: Tu as des vacances en mai?\nB: Oui, il y a beaucoup de jours fériés en mai.\nA: C'est parfait!",exampleSrc:"A: Do you have holidays in May?\nB: Yes, there are many public holidays in May.\nA: That is perfect!",funFact:"May. From Latin 'Maius.' Short, no accent needed."},
        {type:"teach",trg:"juin",src:"June",pos:"noun",gender:"m",note:"Juin = June. Le bac (baccalauréat) is the\nFrench high school exam, held in June.",example:"A: Les examens sont en juin?\nB: Oui, le bac est en juin.\nA: Bon courage!",exampleSrc:"A: Are exams in June?\nB: Yes, the bac is in June.\nA: Good luck!",funFact:"June. From Latin 'Junius.' Silent n."},
        {type:"mc",q:"Which month comes after avril?",opts:["mai","mars","juin","février"],ans:"mai",hint:"Think alphabetically in the calendar. April is the 4th month."},
        {type:"fb",opts:["janvier","février","mars","juin"],hint:"The first month of the year, starting with j.",s:"Mon anniversaire est en {1}. (January)",a:"janvier"},
        {type:"teach",trg:"juillet",src:"July",pos:"noun",gender:"m",note:"Juillet = July. The French national holiday\nis le 14 juillet (Bastille Day).",example:"A: Tu pars en vacances en juillet?\nB: Oui, on va au sud de la France!\nA: Quelle chance!",exampleSrc:"A: Are you going on holiday in July?\nB: Yes, we are going to the south of France!\nA: How lucky!",funFact:"July. From Latin 'Julius' (Julius Caesar's month). Silent t."},
        {type:"teach",trg:"août",src:"August",pos:"noun",gender:"m",note:"Août is pronounced OOT (the a is silent).\nAugust is the main holiday month in France.",example:"A: Beaucoup de magasins ferment en août?\nB: Oui, tout le monde est en vacances.\nA: C'est typiquement français!",exampleSrc:"A: Do many shops close in August?\nB: Yes, everyone is on holiday.\nA: That is typically French!",funFact:"August. From Latin 'Augustus.' Silent t. Circumflex on û = historical silent 'g.'"},
        {type:"teach",trg:"septembre",src:"September",pos:"verb",gender:null,note:"La rentrée = the return (to school/work).\nA key cultural moment in France.",example:"A: La rentrée, c'est en septembre?\nB: Oui, les enfants retournent à l'école.\nA: C'est la fin des vacances!",exampleSrc:"A: Back to school is in September?\nB: Yes, the children go back to school.\nA: It is the end of holidays!",funFact:"Cognate with English 'september'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"octobre",src:"October",pos:"verb",gender:null,note:"Octobre = October.\nAutumn officially begins around September 22.",example:"A: Les feuilles tombent en octobre.\nB: Oui, c'est l'automne.\nA: J'aime les couleurs d'automne.",exampleSrc:"A: The leaves fall in October.\nB: Yes, it is autumn.\nA: I love the autumn colours.",funFact:"Cognate with English 'october'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"novembre",src:"November",pos:"intj",gender:null,note:"Novembre = November.\nLe 11 novembre is a public holiday (Armistice Day).",example:"A: Il fait déjà froid en novembre?\nB: Oui, les jours sont courts et gris.\nA: Vivement Noël!",exampleSrc:"A: Is it already cold in November?\nB: Yes, the days are short and grey.\nA: Roll on Christmas!",funFact:"Cognate with English 'november'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"décembre",src:"December",pos:"verb",gender:null,note:"Décembre = December. The last month.\nNoël = Christmas. Nouvel An = New Year.",example:"A: Noël, c'est le 25 décembre?\nB: Oui, et le Nouvel An, c'est le 31!\nA: J'adore les fêtes!",exampleSrc:"A: Christmas is December 25th?\nB: Yes, and New Year is the 31st!\nA: I love the holidays!",funFact:"Cognate with English 'december'. Many English words were borrowed from French after 1066."},
        {type:"mc",q:"Bastille Day, France's national holiday, falls on the 14th of which month?",opts:["juin","juillet","août","mai"],ans:"juillet",hint:"This midsummer month follows juin and precedes août."},
        {type:"teach",trg:"le printemps",src:"spring",pos:"noun",gender:"m",note:"Le printemps = spring (masculine).\nUse au printemps (NOT en printemps).\nThis is the only season with au.",example:"A: Tu préfères quelle saison?\nB: Le printemps! Les fleurs, le soleil...\nA: Moi aussi, j'adore le printemps.",exampleSrc:"A: Which season do you prefer?\nB: Spring! The flowers, the sun...\nA: Me too, I love spring.",funFact:"Spring (season). Compound: 'prin' (first) + 'temps' (time). Literally 'first-time/season.' Indicates the year's beginning."},
        {type:"teach",trg:"l'été",src:"summer",pos:"noun",gender:"m",note:"L'été = summer (masculine).\nUse en été = in summer.",example:"A: Qu'est-ce que tu fais en été?\nB: Je vais à la plage!\nA: Bonne idée!",exampleSrc:"A: What do you do in summer?\nB: I go to the beach!\nA: Good idea!",funFact:"Summer. Masculine. From Latin 'aestas.' É shows the Latin ae > é shift."},
        {type:"teach",trg:"l'automne",src:"autumn",pos:"noun",gender:"m",note:"L'automne = autumn (masculine).\nUse en automne = in autumn.\nThe final -e is silent.",example:"A: L'automne commence en septembre.\nB: Oui, les feuilles changent de couleur.\nA: C'est une belle saison.",exampleSrc:"A: Autumn starts in September.\nB: Yes, the leaves change colour.\nA: It is a beautiful season.",funFact:"Autumn. Masculine. From Latin 'autumnus.' Silent m+n at end."},
        {type:"teach",trg:"l'hiver",src:"winter",pos:"verb",gender:null,note:"L'hiver = winter (masculine).\nUse en hiver = in winter.",example:"A: Tu aimes l'hiver?\nB: Non, il fait trop froid!\nA: Mais il y a Noël et la neige!",exampleSrc:"A: Do you like winter?\nB: No, it is too cold!\nA: But there is Christmas and snow!",funFact:"Winter. Masculine. From Latin 'hibernum' (winter quarter). Same root as 'hibernation.'"},
        {type:"tip",title:"Seasons with prepositions",text:"Spring is special: au printemps.\nThe other three: en été, en automne, en hiver.\nAll months use en: en janvier, en mars, en décembre."},
        {type:"mc",q:"How do you say 'in spring' in French?",opts:["en printemps","dans le printemps","au printemps","à printemps"],ans:"au printemps",hint:"Spring is the exception among seasons for prepositions."},
        {type:"fb",opts:["automne","hiver","été","printemps"],hint:"The season when leaves change colour and fall.",s:"Les feuilles tombent en {1}. (autumn)",a:"automne"},
        {type:"mc",q:"Which season uses a DIFFERENT preposition from the other three?",opts:["l'été","l'automne","l'hiver","le printemps"],ans:"le printemps",hint:"Three seasons use en, but one uses au."},
        {type:"match",pairs:[{trg:"janvier",src:"January"},{trg:"juillet",src:"July"},{trg:"octobre",src:"October"},{trg:"le printemps",src:"spring"},{trg:"l'hiver",src:"winter"}]},
        {type:"fb",opts:["décembre","novembre","janvier","octobre"],hint:"The twelfth and final month of the year.",s:"Noël est en {1}. (December)",a:"décembre"},
        {type:"mc",q:"When is la rentrée (back to school) in France?",opts:["en septembre","en juin","en janvier","en mars"],ans:"en septembre",hint:"After the long summer holidays, children return to school."}
  ]},
  {id:"fre5l8c",title:"Les Émotions",icon:"😊",xp:25,board:true,steps:[
        {type:"intro",title:"Les Émotions",desc:"Learn to express how you feel in French with a wide range of emotion words.",goals:["Learn 14 emotion adjectives","Understand masculine/feminine forms","Use être + adjective and avoir + noun for emotions"]},
        {type:"teach",trg:"heureux / heureuse",src:"happy",pos:"adj",gender:null,note:"Heureux (m) / heureuse (f): happy.\nJe suis heureux. (man speaking)\nJe suis heureuse. (woman speaking)",example:"A: Comment tu te sens aujourd'hui?\nB: Je suis très heureuse!",exampleSrc:"A: How do you feel today?\nB: I am very happy!",funFact:"Happy (m/f). -eux/-euse pattern. Feminine adds -se."},
        {type:"teach",trg:"triste",src:"sad",pos:"adj",gender:null,note:"Triste: sad.\nSame form for masculine and feminine.\nUn garçon triste. Une fille triste.",example:"A: Pourquoi tu pleures?\nB: Je suis triste. Mon chat est malade.",exampleSrc:"A: Why are you crying?\nB: I am sad. My cat is sick.",funFact:"Sad. Invariable for gender. Plural: tristes."},
        {type:"teach",trg:"fâché / fâchée",src:"angry",pos:"intj",gender:null,note:"Fâché (m) / fâchée (f): angry.\nAlso means upset or cross.\nêtre fâché contre: to be angry at.",example:"A: Papa est fâché?\nB: Oui, il est très fâché.",exampleSrc:"A: Is Dad angry?\nB: Yes, he is very angry.",funFact:"Angry (m/f). From 'se fâcher' (to get angry). Past participle used as adjective. English 'fashion' shares a distant related root (both from 'facere' = to make)."},
        {type:"teach",trg:"fatigué / fatiguée",src:"tired",pos:"adj",gender:null,note:"Fatigué (m) / fatiguée (f): tired.\nTrès fatigué: very tired.\nJe suis fatigué(e) après le travail.",example:"A: Tu veux sortir ce soir?\nB: Non, je suis trop fatiguée.",exampleSrc:"A: Do you want to go out tonight?\nB: No, I am too tired.",funFact:"Tired (m/f). Past participle used as adjective. Feminine adds -e."},
        {type:"teach",trg:"content / contente",src:"pleased / happy",pos:"intj",gender:null,note:"Content (m) / contente (f): pleased, happy.\nSimilar to heureux but lighter.\nContent de + infinitif: happy to do.",example:"A: Tu as eu le poste?\nB: Oui! Je suis très contente!",exampleSrc:"A: Did you get the job?\nB: Yes! I am very pleased!",funFact:"Pleased / happy (m/f). From Latin 'contentus' (satisfied). Same root as English 'content' (satisfied). Feminine adds -e and sounds the final 't.'"},
        {type:"teach",trg:"avoir peur",src:"to be afraid",pos:"verb",gender:null,note:"Avoir peur: to be afraid (literally 'to have fear').\nJ'ai peur. Tu as peur. Il a peur.\nAvoir peur de: to be afraid of.",example:"A: Tu aimes les araignées?\nB: Non, j'ai peur des araignées!",exampleSrc:"A: Do you like spiders?\nB: No, I am afraid of spiders!",funFact:"'To be afraid.' Literally 'to have fear.' Uses 'avoir' where English uses 'to be.' Classic French idiom-structure: peur, faim, soif, chaud all use 'avoir.'"},
        {type:"tip",title:"Être + adjectif ou avoir + nom?",deepDive:"The avoir + noun pattern is common in French for physical and emotional states: avoir faim (to be hungry), avoir soif (to be thirsty), avoir chaud (to be hot), avoir froid (to be cold), avoir peur (to be afraid), avoir honte (to be ashamed). English uses 'to be' for all of these, but French distinguishes between states you ARE and states you HAVE.",text:"French uses two patterns for emotions:\n\n1. être + adjective (most emotions):\n- Je suis triste. (I am sad.)\n- Elle est contente. (She is happy.)\n\n2. avoir + noun (some expressions):\n- J'ai peur. (I am afraid. Lit: I have fear.)\n- J'ai honte. (I am ashamed. Lit: I have shame.)\n\nWith être, the adjective agrees with the subject:\n- Il est content. Elle est contente."},
        {type:"teach",trg:"nerveux / nerveuse",src:"nervous",pos:"intj",gender:null,note:"Nerveux (m) / nerveuse (f): nervous.\nSimilar pattern to heureux/heureuse.\n-eux -> -euse for feminine.",example:"A: Tu as un examen demain?\nB: Oui, je suis très nerveuse.",exampleSrc:"A: Do you have an exam tomorrow?\nB: Yes, I am very nervous.",funFact:"Nervous (m/f). -eux/-euse adjective pair; productive French pattern: heureux/heureuse, sérieux/sérieuse. Derived from 'nerf' (nerve)."},
        {type:"teach",trg:"fier / fière",src:"proud",pos:"intj",gender:null,note:"Fier (m) / fière (f): proud.\nêtre fier de: to be proud of.\nJe suis fier de toi: I am proud of you.",example:"A: Mon fils a réussi son examen!\nB: Tu dois être très fier.",exampleSrc:"A: My son passed his exam!\nB: You must be very proud.",funFact:"Proud (m/f). From Latin 'ferus' (wild, fierce). English 'fierce' is the same root. Pride and fierceness were originally one concept."},
        {type:"teach",trg:"surpris / surprise",src:"surprised",pos:"intj",gender:null,note:"Surpris (m) / surprise (f): surprised.\nQuelle surprise! What a surprise!",example:"A: C'est une fête pour moi?\nB: Oui! Tu es surprise?",exampleSrc:"A: Is this a party for me?\nB: Yes! Are you surprised?",funFact:"Surprised (m/f). Past participle of 'surprendre.' English 'surprise' borrowed from French. Feminine adds -e; pronunciation changes due to -e."},
        {type:"teach",trg:"ennuyé / ennuyée",src:"bored",pos:"verb",gender:null,note:"Ennuyé (m) / ennuyée (f): bored.\nAlso: s'ennuyer (to be bored, verb).\nC'est ennuyeux: it's boring.",example:"A: Comment est le film?\nB: Pas bien. Je suis ennuyé.",exampleSrc:"A: How is the movie?\nB: Not good. I am bored.",funFact:"Bored (m/f). Past participle used as adjective. Agrees with subject gender. 'Je suis ennuyé' (m) / 'Je suis ennuyée' (f)."},
        {type:"teach",trg:"inquiet / inquiète",src:"worried",pos:"intj",gender:null,note:"Inquiet (m) / inquiète (f): worried.\nNote the accent change: -et -> -ète.\nêtre inquiet pour: worried about.",example:"A: Ta mère n'appelle pas?\nB: Non, je suis inquiète.",exampleSrc:"A: Your mother isn't calling?\nB: No, I am worried.",funFact:"Worried (m/f). From Latin 'inquietus' (not-at-rest). 'In-' (not) + 'quiet.' Same root as English 'inquiet' (archaic)."},
        {type:"teach",trg:"excité / excitée",src:"excited",pos:"intj",gender:null,note:"Excité (m) / excitée (f): excited.\nAlso: enthousiaste (enthusiastic).\nJe suis excité(e) pour les vacances.",example:"A: Les vacances commencent demain!\nB: Oui, je suis très excité!",exampleSrc:"A: The holidays start tomorrow!\nB: Yes, I am very excited!",funFact:"Excited (m/f). From 'exciter' (to excite). Note: French 'excité' can have sexual connotation in some contexts; use 'enthousiasmé' for neutral 'excited.'"},
        {type:"teach",trg:"gêné / gênée",src:"embarrassed",pos:"intj",gender:null,note:"Gêné (m) / gênée (f): embarrassed.\nAlso means uncomfortable.\nC'est gênant: it's embarrassing.",example:"A: Tu es tout rouge!\nB: Oui, je suis gêné.",exampleSrc:"A: You are all red!\nB: Yes, I am embarrassed.",funFact:"Embarrassed (m/f). From 'gêner' (to bother/embarrass). English 'gene' is unrelated; 'gêne' comes from Old French for 'torture.' Ironic modern softening."},
        {type:"teach",trg:"seul / seule",src:"lonely / alone",pos:"intj",gender:null,note:"Seul (m) / seule (f): alone, lonely.\nêtre seul: to be alone.\nse sentir seul: to feel lonely.",example:"A: Tu habites avec quelqu'un?\nB: Non, je vis seule. Parfois je me sens seule.",exampleSrc:"A: Do you live with someone?\nB: No, I live alone. Sometimes I feel lonely.",funFact:"Lonely / alone (m/f). From Latin 'solus' (alone). Same root as English 'sole,' 'solo,' 'solitary.' Very productive."},
        {type:"mc",q:"Comment dit-on 'I am happy' (said by a woman)?",opts:["Je suis heureuse","Je suis heureux","J'ai heureuse","Je suis contente"],ans:"Je suis heureuse",hint:"A woman uses the feminine form of the adjective with être."},
        {type:"mc",q:"How do you say 'I am afraid' in French?",opts:["Je suis peur","J'ai peur","J'ai effrayé","Je suis effrayé"],ans:"J'ai peur",hint:"Fear uses the avoir + noun pattern, not être + adjective."},
        {type:"fb",opts:["fatigué","fatiguée","triste","fâché"],hint:"Your brother is masculine. Choose the masculine form of tired.",s:"Mon frère est très {1} après le match. (tired, masculine)",a:"fatigué"},
        {type:"match",pairs:[{trg:"heureux",src:"happy"},{trg:"triste",src:"sad"},{trg:"fâché",src:"angry"},{trg:"fatigué",src:"tired"}]},
        {type:"mc",q:"Elle est ___ de son fils. (proud, feminine)",opts:["fiers","fier","fière","fières"],ans:"fière",hint:"Elle requires the feminine singular form of this adjective."},
        {type:"fb",opts:["surprise","surpris","surprisée","surprises"],hint:"The subject is feminine. The feminine of surpris adds an -e.",s:"Tu es {1}? Tu ne savais pas? (surprised, feminine)",a:"surprise"},
        {type:"mc",q:"Comment dit-on 'I am worried' (said by a man)?",opts:["Je suis nerveux","Je suis inquiète","J'ai inquiet","Je suis inquiet"],ans:"Je suis inquiet",hint:"A man uses the masculine form. Note the spelling without accent."},
        {type:"fb",opts:["excité","excitée","ennuyé","nerveux"],hint:"Use the masculine form of the word meaning thrilled or eager.",s:"Les vacances commencent demain. Je suis très {1}! (excited, masculine)",a:"excité"},
        {type:"match",pairs:[{trg:"nerveux",src:"nervous"},{trg:"surpris",src:"surprised"},{trg:"ennuyé",src:"bored"},{trg:"gêné",src:"embarrassed"}]},
        {type:"mc",q:"Marie est toute rouge. Elle est ___.",opts:["gênée","gêné","fâchée","fière"],ans:"gênée",hint:"Marie is blushing. She feels self-conscious. Use feminine form."},
        {type:"drag_fill",hint:"He uses masculine, she uses feminine. Same adjective, different endings.",s:"Il est {1} et elle est {2}.",blanks:{"1":"content","2":"contente"},pool:["content","contente","contents","contentes"]},
        {type:"fb",opts:["seule","seul","triste","ennuyée"],hint:"The feminine form of alone adds an -e to the masculine form.",s:"Je n'aime pas être {1}. J'appelle mes amis. (alone, feminine)",a:"seule"}
  ]},
  {id:"fre5l8",title:"Révision",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Unit 5 Review",desc:"Review all of Unit 5: -er verbs, time, reflexive verbs, daily routine, days of the week, negation, and weekly descriptions.",goals:["Review -er conjugation","Test time expressions","Combine routine vocabulary with negation"]},
        {type:"mc",q:"The -er verb meaning 'to work' has a conjugation base. What is it?",opts:["travaill","travail","trav","travailler"],ans:"travaill",hint:"Remove the two-letter infinitive ending to find the stem used in conjugation."},
        {type:"fb",opts:["demie","quart","dix","midi"],hint:"Half past: the word for half.",s:"Il est trois heures et {1}. (3:30)",a:"demie"},
        {type:"mc",q:"Reflexive pronouns go:",opts:["After the verb","Before the verb","After the subject","Nowhere specific"],ans:"Before the verb",hint:"Je ME lève. Tu TE couches. Notice where ME and TE sit."},
        {type:"match",pairs:[{trg:"se lever",src:"to get up"},{trg:"se coucher",src:"to go to bed"},{trg:"se laver",src:"to wash oneself"},{trg:"se réveiller",src:"to wake up"}]},
        {type:"mc",q:"'Je vais au travail' uses which irregular verb?",opts:["Être","Avoir","Aller","Faire"],ans:"Aller",hint:"'Vais' is the je form. Which infinitive does it come from?"},
        {type:"fb",opts:["mange","manges","manger","mangez"],hint:"I do not eat: ne + verb + pas.",s:"Je ne {1} pas de viande.",a:"mange"},
        {type:"mc",q:"French days of the week are:",opts:["Capitalized","Irregular","Feminine","Lowercase"],ans:"Lowercase",hint:"Unlike English, French does not capitalize these."},
        {type:"mc",q:"'Le lundi' means:",opts:["Every Monday","Last Monday","This Monday","Next Monday"],ans:"Every Monday",hint:"Le + day = habitual, e... week."},
        {type:"fb",opts:["se","me","te","nous"],hint:"She gets up: third person reflexive pronoun.",s:"Elle {1} lève à sept heures. (reflexive)",a:"se"},
        {type:"match",pairs:[{trg:"lundi",src:"Monday"},{trg:"jeudi",src:"Thursday"},{trg:"samedi",src:"Saturday"},{trg:"dimanche",src:"Sunday"}]},
        {type:"mc",q:"After 'ne...pas', partitive articles become:",opts:["Le/la","De/d'","Du/de la","Un/une"],ans:"De/d'",hint:"Negation strips partitive to just de."},
        {type:"fb",opts:["tous","tout","toute","chaque"],hint:"Every day: ___ les jours.",s:"Je fais du sport {1} les jours.",a:"tous"},
        {type:"mc",q:"Frequency adverbs go:",opts:["Before the subject","Before the verb","After the verb","At the end"],ans:"After the verb",hint:"Je mange SOUVENT. Je travaille RAREMENT."},
        {type:"mc",q:"'Il est midi' means:",opts:["It is midnight","It is twelve hours","It is midday meal","It is noon"],ans:"It is noon",hint:"Midi = 12:00 PM. Minuit = 12:00 AM."},
        {type:"fb",opts:["de","à","en","du"],hint:"From nine to five: from = de.",s:"Je travaille {1} neuf heures à cinq heures.",a:"de"},
        {type:"mc",q:"In casual spoken French, which of the two parts of 'pas + X' is commonly omitted?",opts:["Ne","Pas","Both","Neither"],ans:"Ne",hint:"Informally, speakers keep only the word that carries the negative force."},
        {type:"mc",q:"'Prendre le petit déjeuner' means:",opts:["To take breakfast away","To have breakfast","To make breakfast","To skip breakfast"],ans:"To have breakfast",hint:"Prendre = to take/have. Used for meals."},
        {type:"fb",opts:["puis","enfin","avant","d'abord"],hint:"First I wake up, THEN I get up. The second sequencer.",s:"D'abord je me réveille, {1} je me lève.",a:"puis"}
  ,{type:"match",pairs:[{trg:"le week-end",src:"the weekend"},{trg:"de ... à ...",src:"from ... to ..."},{trg:"novembre",src:"November"}]}]}
, COVERAGE_U05]};
